    q = (request.args.get("q") or "").strip()
    role = (request.args.get("role") or "").strip()

    filt: Dict[str, Any] = {}
    if q:
        filt["$or"] = [{"username": {"$regex": q, "$options": "i"}}, {"email": {"$regex": q, "$options": "i"}}]
