@app.get("/documents")
def query_documents():
    page, page_size = get_pagination()
    sort = parse_sort(default="-updated_at")

    q = (request.args.get("q") or "").strip()
    author_id = (request.args.get("author_id") or "").strip()
    status = (request.args.get("status") or "").strip()
    tag = (request.args.get("tag") or "").strip()
    slug = (request.args.get("slug") or "").strip()
    created_from = (request.args.get("created_from") or "").strip()
    created_to = (request.args.get("created_to") or "").strip()
    use_text = request.args.get("use_text", "false").lower() in ("1", "true", "yes", "on")

    filt: Dict[str, Any] = {}
    if slug:
        filt["slug"] = slug
    if author_id:
        filt["author_id"] = _oid(author_id)
    if status:
        filt["status"] = status
    if tag:
        filt["tags"] = tag

    if created_from or created_to:
        rng: Dict[str, Any] = {}
        if created_from:
            try:
                rng["$gte"] = datetime.fromisoformat(created_from.replace("Z", "+00:00")).replace(tzinfo=None)
            except Exception:
                raise BadRequest("created_from must be ISO format")
        if created_to:
            try:
                rng["$lte"] = datetime.fromisoformat(created_to.replace("Z", "+00:00")).replace(tzinfo=None)
            except Exception:
                raise BadRequest("created_to must be ISO format")
        filt["created_at"] = rng

    if q:
        if use_text:
            filt["$text"] = {"$search": q}
        else:
            filt["$or"] = [
                {"title": {"$regex": q, "$options": "i"}},
                {"content": {"$regex": q, "$options": "i"}},
                {"tags": {"$regex": q, "$options": "i"}},
                {"slug": {"$regex": q, "$options": "i"}},
            ]

    projection = None
    if use_text and q:
        projection = {"score": {"$meta": "textScore"}}
        sort = [("score", {"$meta": "textScore"}), ("updated_at", DESCENDING)]

    cur = documents.find(filt, projection=projection).sort(sort).skip((page - 1) * page_size).limit(page_size)
    items = [serialize_doc(d) for d in cur]
    total = documents.count_documents(filt)
    return jsonify({"items": items, "page": page, "page_size": page_size, "total": total})


