@app.get("/analytics/documents/by-status")
def analytics_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}, "last_updated": {"$max": "$updated_at"}}},
        {"$sort": {"count": -1, "_id": 1}},
    ]
    rows = list(documents.aggregate(pipeline))
    rows = [{"status": r["_id"], "count": r["count"], "last_updated": _serialize_value(r.get("last_updated"))} for r in rows]
    return jsonify({"items": rows})


@app.get("/analytics/documents/by-tag")
def analytics_by_tag():
    limit = request.args.get("limit", "20")
    try:
        limit_i = max(1, min(int(limit), 200))
    except ValueError:
        raise BadRequest("limit must be an integer")

    status = (request.args.get("status") or "").strip()
    match: Dict[str, Any] = {}
    if status:
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})
    pipeline.extend(
        [
            {"$unwind": {"path": "$tags", "preserveNullAndEmptyArrays": False}},
            {"$group": {"_id": "$tags", "count": {"$sum": 1}, "last_updated": {"$max": "$updated_at"}}},
            {"$sort": {"count": -1, "_id": 1}},
            {"$limit": limit_i},
        ]
    )
    rows = list(documents.aggregate(pipeline))
    rows = [{"tag": r["_id"], "count": r["count"], "last_updated": _serialize_value(r.get("last_updated"))} for r in rows]
    return jsonify({"items": rows})


