@app.get("/analytics/documents/timeline")
def analytics_timeline():
    interval = (request.args.get("interval") or "day").strip().lower()
    if interval not in ("day", "month"):
        raise BadRequest("interval must be 'day' or 'month'")

    status = (request.args.get("status") or "").strip()
    match: Dict[str, Any] = {}
    if status:
        match["status"] = status

    fmt = "%Y-%m-%d" if interval == "day" else "%Y-%m"
    pipeline: List[Dict[str, Any]] = []
    if match:
        pipeline.append({"$match": match})
    pipeline.extend(
        [
            {"$addFields": {"bucket": {"$dateToString": {"format": fmt, "date": "$created_at"}}}},
            {"$group": {"_id": "$bucket", "count": {"$sum": 1}}},
            {"$sort": {"_id": 1}},
            {"$project": {"_id": 0, "bucket": "$_id", "count": 1}},
        ]
    )
    rows = list(documents.aggregate(pipeline))
    return jsonify({"items": rows})


